+import { html, nothing } from "lit";
+import type { ConfigUiHint, ConfigUiHints } from "../types";
+
+export type ConfigFormProps = {
+  schema: unknown | null;
+  uiHints: ConfigUiHints;
+  value: Record<string, unknown> | null;
+  onPatch: (path: Array<string | number>, value: unknown) => void;
+};
+
+type JsonSchema = {
+  type?: string | string[];
+  title?: string;
+  description?: string;
+  properties?: Record<string, JsonSchema>;
+  items?: JsonSchema | JsonSchema[];
+  enum?: unknown[];
+  default?: unknown;
+  anyOf?: JsonSchema[];
+  oneOf?: JsonSchema[];
+  allOf?: JsonSchema[];
+};
+
+export function renderConfigForm(props: ConfigFormProps) {
+  if (!props.schema) {
+    return html`<div class="muted">Schema unavailable.</div>`;
+  }
+  const schema = props.schema as JsonSchema;
+  const value = props.value ?? {};
+  if (schemaType(schema) !== "object" || !schema.properties) {
+    return html`<div class="callout danger">Unsupported schema. Use Raw.</div>`;
+  }
+  const entries = Object.entries(schema.properties);
+  const sorted = entries.sort((a, b) => {
+    const orderA = hintForPath([a[0]], props.uiHints)?.order ?? 0;
+    const orderB = hintForPath([b[0]], props.uiHints)?.order ?? 0;
+    if (orderA !== orderB) return orderA - orderB;
+    return a[0].localeCompare(b[0]);
+  });
+
+  return html`
+    <div class="config-form">
+      ${sorted.map(([key, node]) =>
+        renderNode({
+          schema: node,
+          value: (value as Record<string, unknown>)[key],
+          path: [key],
+          hints: props.uiHints,
+          onPatch: props.onPatch,
+        }),
+      )}
+    </div>
+  `;
+}
+
+function renderNode(params: {
+  schema: JsonSchema;
+  value: unknown;
+  path: Array<string | number>;
+  hints: ConfigUiHints;
+  onPatch: (path: Array<string | number>, value: unknown) => void;
+}) {
+  const { schema, value, path, hints, onPatch } = params;
+  const type = schemaType(schema);
+  const hint = hintForPath(path, hints);
+  const label = hint?.label ?? schema.title ?? humanize(String(path.at(-1)));
+  const help = hint?.help ?? schema.description;
+
+  if (schema.anyOf || schema.oneOf || schema.allOf) {
+    return html`<div class="callout danger">
+      ${label}: unsupported schema node. Use Raw.
+    </div>`;
+  }
+
+  if (type === "object") {
+    const props = schema.properties ?? {};
+    const entries = Object.entries(props);
+    if (entries.length === 0) return nothing;
+    return html`
+      <fieldset class="field-group">
+        <legend>${label}</legend>
+        ${help ? html`<div class="muted">${help}</div>` : nothing}
+        ${entries.map(([key, node]) =>
+          renderNode({
+            schema: node,
+            value: value && typeof value === "object" ? (value as any)[key] : undefined,
+            path: [...path, key],
+            hints,
+            onPatch,
+          }),
+        )}
+      </fieldset>
+    `;
+  }
+
+  if (type === "array") {
+    const itemSchema = Array.isArray(schema.items)
+      ? schema.items[0]
+      : schema.items;
+    const arr = Array.isArray(value) ? value : [];
+    return html`
+      <div class="field">
+        <div class="row" style="justify-content: space-between;">
+          <span>${label}</span>
+          <button
+            class="btn"
+            @click=${() => {
+              const next = [...arr, defaultValue(itemSchema)];
+              onPatch(path, next);
+            }}
+          >
+            Add
+          </button>
+        </div>
+        ${help ? html`<div class="muted">${help}</div>` : nothing}
+        ${arr.map((entry, index) =>
+          html`<div class="array-item">
+            ${itemSchema
+              ? renderNode({
+                  schema: itemSchema,
+                  value: entry,
