+    `;
+  }
+
+  if (type === "number" || type === "integer") {
+    return html`
+      <label class="field">
+        <span>${label}</span>
+        ${help ? html`<div class="muted">${help}</div>` : nothing}
+        <input
+          type="number"
+          .value=${value == null ? "" : String(value)}
