+}
+
+function schemaType(schema: JsonSchema): string | undefined {
+  if (!schema) return undefined;
+  if (Array.isArray(schema.type)) {
+    const filtered = schema.type.filter((t) => t !== "null");
+    return filtered[0] ?? schema.type[0];
+  }
+  return schema.type;
