+
+function isSensitivePath(path: Array<string | number>): boolean {
+  const key = pathKey(path).toLowerCase();
+  return (
+    key.includes("token") ||
+    key.includes("password") ||
+    key.includes("secret") ||
+    key.includes("apikey") ||
+    key.endsWith("key")
+  );
+}

